glsl3.vert:
precision highp float;
layout(std140) uniform CCGlobal {
  highp   vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_nativeSize;
  mediump vec4 cc_probeInfo;
  mediump vec4 cc_debug_view_mode;
};
layout(std140) uniform CCCamera {
  highp   mat4 cc_matView;
  highp   mat4 cc_matViewInv;
  highp   mat4 cc_matProj;
  highp   mat4 cc_matProjInv;
  highp   mat4 cc_matViewProj;
  highp   mat4 cc_matViewProjInv;
  highp   vec4 cc_cameraPos;
  mediump vec4 cc_surfaceTransform;
  mediump vec4 cc_screenScale;
  mediump vec4 cc_exposure;
  mediump vec4 cc_mainLitDir;
  mediump vec4 cc_mainLitColor;
  mediump vec4 cc_ambientSky;
  mediump vec4 cc_ambientGround;
  mediump vec4 cc_fogColor;
  mediump vec4 cc_fogBase;
  mediump vec4 cc_fogAdd;
  mediump vec4 cc_nearFar;
  mediump vec4 cc_viewPort;
};
#if USE_LOCAL
  layout(std140) uniform CCLocal {
    highp mat4 cc_matWorld;
    highp mat4 cc_matWorldIT;
    highp vec4 cc_lightingMapUVParam;
    highp vec4 cc_localShadowBias;
    highp vec4 cc_reflectionProbeData1;
    highp vec4 cc_reflectionProbeData2;
    highp vec4 cc_reflectionProbeBlendData1;
    highp vec4 cc_reflectionProbeBlendData2;
  };
#endif
in vec3 a_position;
in vec2 a_texCoord;
in vec4 a_color;
out vec2 v_uv;
out vec4 v_color;
vec4 virt () {
  vec4 pos = vec4(a_position, 1);
  #if USE_LOCAL
    pos = cc_matWorld * pos;
  #endif
  pos = cc_matViewProj * pos;
  v_uv = a_texCoord;
  v_color = a_color;
  return pos;
}
void main() { gl_Position = virt(); }

glsl3.frag:
precision highp float;
layout(std140) uniform CCGlobal {
  highp   vec4 cc_time;
  mediump vec4 cc_screenSize;
  mediump vec4 cc_nativeSize;
  mediump vec4 cc_probeInfo;
  mediump vec4 cc_debug_view_mode;
};
layout(std140) uniform CCCamera {
  highp   mat4 cc_matView;
  highp   mat4 cc_matViewInv;
  highp   mat4 cc_matProj;
  highp   mat4 cc_matProjInv;
  highp   mat4 cc_matViewProj;
  highp   mat4 cc_matViewProjInv;
  highp   vec4 cc_cameraPos;
  mediump vec4 cc_surfaceTransform;
  mediump vec4 cc_screenScale;
  mediump vec4 cc_exposure;
  mediump vec4 cc_mainLitDir;
  mediump vec4 cc_mainLitColor;
  mediump vec4 cc_ambientSky;
  mediump vec4 cc_ambientGround;
  mediump vec4 cc_fogColor;
  mediump vec4 cc_fogBase;
  mediump vec4 cc_fogAdd;
  mediump vec4 cc_nearFar;
  mediump vec4 cc_viewPort;
};
in vec2 v_uv;
in vec4 v_color;
#if USE_TEXTURE
  uniform sampler2D mainTexture;
#endif
layout(std140) uniform Constant {
  vec4 color1;
  vec4 color2;
  vec4 color3;
  vec4 color4;
  vec4 color5;
  vec4 color6;
  vec4 color7;
  vec4 color8;
  float totalFillLevel;
  float activeLayers;
  float maxLayers;
  float liquidBottom;
  float liquidTop;
  float waveHeight;
  float waveSpeed;
  float rotation;
  float alphaThreshold;
};
vec4 frag () {
  vec4 o = v_color;
  #if USE_TEXTURE
    vec4 texColor = texture(mainTexture, v_uv);
    if (texColor.a < alphaThreshold) discard;
    o.a *= texColor.a;
  #endif
  if (activeLayers < 0.5 || totalFillLevel <= 0.001) {
    discard;
  }
  float minFill = clamp(liquidBottom, 0.0, 1.0);
  float maxFill = clamp(liquidTop, minFill + 0.001, 1.0);
  float displayFill = mix(minFill, maxFill, clamp(totalFillLevel, 0.0, 1.0));
  vec2 fixedUV = vec2(v_uv.x, 1.0 - v_uv.y);
  if (fixedUV.y > maxFill || fixedUV.y < minFill) {
      discard;
  }
  vec2 uv = fixedUV - vec2(0.5);
  float cosR = cos(rotation);
  float sinR = sin(rotation);
  float rotatedY = (uv.x * sinR + uv.y * cosR) + 0.5;
  float time = cc_time.x * waveSpeed;
  float wave = sin((uv.x * cosR - uv.y * sinR) * 15.0 + time) * waveHeight;
  if (rotatedY > displayFill + wave) {
      discard;
  }
  float ratio = clamp((rotatedY - minFill) / max(maxFill - minFill, 0.001), 0.0, 1.0);
  float layerIndex = floor(ratio * maxLayers);
  if (layerIndex >= maxLayers) layerIndex = maxLayers - 1.0;
  vec4 waterColor;
  if (layerIndex < 1.0) waterColor = color1;
  else if (layerIndex < 2.0) waterColor = color2;
  else if (layerIndex < 3.0) waterColor = color3;
  else if (layerIndex < 4.0) waterColor = color4;
  else if (layerIndex < 5.0) waterColor = color5;
  else if (layerIndex < 6.0) waterColor = color6;
  else if (layerIndex < 7.0) waterColor = color7;
  else waterColor = color8;
  o.rgb *= waterColor.rgb;
  o.a *= waterColor.a;
  return o;
}
layout(location = 0) out vec4 cc_FragColor;
void main() { cc_FragColor = frag(); }

